import { codes } from "micromark-util-symbol/codes";

import type { Code } from "micromark-util-types";

function findCode(code: Code) {
  return Object.keys(codes).find((key) => codes[key as keyof typeof codes] === code);
}

// Guard against browser/isolated envs where `process` is not defined.
function isDevEnv() {
  const maybeProcess = (globalThis as { process?: { env?: { NODE_ENV?: string } } }).process;
  return maybeProcess?.env?.NODE_ENV === "development";
}

const ENABLE_DEBUG = false;
export function debug(name: string, code: Code, extra?: string | number) {
  if (isDevEnv() && ENABLE_DEBUG) {
    console.info(`[${name}]`, findCode(code), extra || "");
  }
}

export function warn(name: string, code: Code) {
  if (isDevEnv() && ENABLE_DEBUG) {
    console.warn(name, findCode(code));
  }
}
